//! MS-OI29500 §17.3.1 + MS-DOCX §2.3: Microsoft implementation notes for
//! paragraph properties.
//!
//! These tests encode behaviors documented in Microsoft's implementation notes
//! (MS-OI29500) and Word extensions (MS-DOCX) where Word's actual behavior
//! diverges from or supplements the base ISO 29500 spec.
//!
//! Fixture DOCX files are generated by
//! `testdata/spec-compliance/create_ms_para_props.py`.

use stemma::Alignment;

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/ms-paragraph-props";

// =========================================================================
// Default paragraph alignment is Left
// =========================================================================

/// MS-OI29500 2.1.45 §17.3.1.13: When no jc element is specified anywhere
/// in the style hierarchy, Word applies left alignment as the default.
///
/// The ISO spec says "no alignment is applied" but Word always defaults
/// to left. Our code currently returns `None` for alignment when no jc
/// is specified, which is technically per ISO but diverges from Word.
///
/// Fixture: jc-default-left
///   P0: no style, no direct jc
///   P1: CenterStyle with jc=center
///   P2: Normal style, no jc
#[test]
fn ms_p01_jc_default_left_when_unspecified() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "jc-default-left");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 3,
        "expected at least 3 paragraphs, got {}",
        paras.len()
    );

    // P0: no alignment specified — Word defaults to Left
    assert_eq!(
        paras[0].align,
        Some(Alignment::Left),
        "P0: Word defaults to Left alignment when jc is unspecified (MS-OI29500 2.1.45). \
         Our code returns None, but Word always applies Left."
    );

    // P1: CenterStyle has jc=center — should resolve center
    assert_eq!(
        paras[1].align,
        Some(Alignment::Center),
        "P1: CenterStyle defines jc=center, should resolve to Center"
    );

    // P2: Normal style, no jc — Word defaults to Left
    assert_eq!(
        paras[2].align,
        Some(Alignment::Left),
        "P2: Normal style with no jc — Word defaults to Left (MS-OI29500 2.1.45)"
    );
}

// =========================================================================
// keepLines ignored inside tables
// =========================================================================

/// MS-OI29500 2.1.46 §17.3.1.14: Word ignores the keepLines property when
/// rendering paragraphs inside a table cell.
///
/// The ISO spec says keepLines applies to all paragraphs, but Word
/// specifically ignores it in table context. This means a consumer that
/// respects keepLines for table paragraphs would diverge from Word behavior.
///
/// Fixture: keeplines-in-table
///   P0: keepLines outside table (should be honored)
///   P1: keepLines inside table cell (Word ignores)
///   P2: keepLines outside table (control)
#[test]
fn ms_p02_keeplines_ignored_in_table() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "keeplines-in-table");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 3,
        "expected at least 3 paragraphs (2 body + 1 table cell), got {}",
        paras.len()
    );

    // P0: keepLines outside table — should be Some(true)
    assert_eq!(
        paras[0].keep_lines,
        Some(true),
        "P0: keepLines outside table should be Some(true)"
    );

    // P1: keepLines inside table — Word IGNORES it at render (MS-OI29500
    // 2.1.46), but that is a consumption rule, not a save rewrite: Word
    // preserves the authored markup verbatim on save, and so must we. The
    // model keeps the authored value; renderers apply the ignore-rule.
    assert_eq!(
        paras[1].keep_lines,
        Some(true),
        "P1: authored keepLines inside a table cell stays in the model \
         (render-time ignore-rule, not a save rewrite; MS-OI29500 2.1.46)"
    );

    // P2: keepLines outside table — should be Some(true)
    assert_eq!(
        paras[2].keep_lines,
        Some(true),
        "P2: keepLines outside table (control) should be Some(true)"
    );
}

// =========================================================================
// widowControl ignored inside tables
